import type { ShipdeskConfig } from "../types.js";

/**
 * Generate the Electron main process file (`main.cjs`).
 *
 * The generated file handles different deployment topologies:
 * - backend-serves-frontend: Backend serves both API and static files
 * - frontend-static-separate: Frontend is separate static build, needs its own server
 * - ssr-framework: Not supported, fails with clear error
 * - unsupported: Not supported, fails with clear error
 */
export function generateElectronMain(config: ShipdeskConfig): string {
  const title = toTitleCase(config.name);
  const topology = config.topology;
  const lines: string[] = [];

  lines.push(
    "// Generated by shipdesk — do not edit manually",
    '// @ts-check',
    'const { app, BrowserWindow, shell, dialog, utilityProcess } = require("electron");',
    'const path = require("path");',
    'const http = require("http");',
    'const fs = require("fs");',
    "",
    "const API_PORT = " + config.backend.devPort + ";",
    "const FRONTEND_PORT = " + config.frontend.devPort + ";",
    "const TOPOLOGY = " + JSON.stringify(topology) + ";",
    "const isDev = !app.isPackaged;",
    "",
    "const gotSingleInstanceLock = app.requestSingleInstanceLock();",
    "if (!gotSingleInstanceLock) {",
    "  app.quit();",
    "}",
    "",
    "let mainWindow = null;",
    "let apiProcess = null;",
    "let staticServer = null;",
    "",
  );

  lines.push(
    "// ---------------------------------------------------------------------------",
    "// Utility functions",
    "// ---------------------------------------------------------------------------",
    "function waitForServer(url, timeoutMs = 15000) {",
    "  return new Promise((resolve, reject) => {",
    "    const start = Date.now();",
    "    const check = () => {",
    "      const req = http.get(url, (res) => {",
    "        if (res.statusCode && res.statusCode < 500) {",
    "          resolve();",
    "        } else if (Date.now() - start > timeoutMs) {",
    "          reject(new Error(\"Timed out waiting for server.\"));",
    "        } else {",
    "          setTimeout(check, 300);",
    "        }",
    "      });",
    "      req.on(\"error\", () => {",
    "        if (Date.now() - start > timeoutMs) {",
    "          reject(new Error(\"Timed out waiting for server.\"));",
    "        } else {",
    "          setTimeout(check, 300);",
    "        }",
    "      });",
    "      req.end();",
    "    };",
    "    check();",
    "  });",
    "}",
    "",
    "function showErrorAndQuit(message) {",
    "  console.error(\"[shipdesk]\", message);",
    "  dialog.showErrorBox(\"Startup Error\", message);",
    "  app.exit(1);",
    "}",
    "",
  );

  if (topology === "unsupported" || topology === "ssr-framework") {
    lines.push(
      "// ---------------------------------------------------------------------------",
      "// Unsupported topology",
      "// ---------------------------------------------------------------------------",
      "if (gotSingleInstanceLock) {",
      "  app.whenReady().then(() => {",
      "    showErrorAndQuit(\"Topology '" + topology + "' is not supported by shipdesk.\\n\\n\" +",
      "      \"Please ensure your backend serves static files or use a static frontend export.\");",
      "  });",
      "}",
    );
  } else if (topology === "backend-serves-frontend") {
    lines.push(...generateBackendServesFrontend(config));
  } else if (topology === "frontend-static-separate") {
    lines.push(...generateFrontendStaticSeparate(config));
  } else if (topology === "frontend-only-static") {
    lines.push(...generateFrontendOnlyStatic(config));
  }

  return lines.join("\n");
}

function generateBackendServesFrontend(config: ShipdeskConfig): string[] {
  const title = toTitleCase(config.name);
  return [
    "// ---------------------------------------------------------------------------",
    "// Topology: backend-serves-frontend",
    "// Backend serves both API and frontend static files",
    "// ---------------------------------------------------------------------------",
    "",
    "async function startApiServer() {",
    "  if (isDev) {",
    "    await waitForServer(\"http://localhost:\" + FRONTEND_PORT, 30000);",
    "    console.log(\"[shipdesk] Frontend ready on port\", FRONTEND_PORT);",
    "    return;",
    "  }",
    "",
    '  const serverPath = path.join(process.resourcesPath, "server", "server.mjs");',
    "  let serverStderr = \"\";",
    "  apiProcess = utilityProcess.fork(serverPath, [], {",
    "    env: { ...process.env, PORT: String(API_PORT), NODE_ENV: \"production\" },",
    "    cwd: path.dirname(serverPath),",
    "    stdio: \"pipe\",",
    '    serviceName: "shipdesk-backend",',
    "  });",
    "",
    '  apiProcess.on("spawn", () => console.log("[server] spawned"));',
    '  apiProcess.stdout?.on("data", (d) => console.log("[server]", d.toString().trim()));',
    '  apiProcess.stderr?.on("data", (d) => {',
    "    serverStderr += d.toString();",
    '    console.error("[server:err]", d.toString().trim());',
    "  });",
    '  apiProcess.on("exit", (code) => {',
    '    console.log("[server] exited with code", code);',
    "    apiProcess = null;",
    "  });",
    "",
    "  await Promise.race([",
    "    waitForServer(\"http://localhost:\" + API_PORT),",
    "    new Promise((_, reject) => {",
    '      apiProcess.once("exit", (code) => {',
    "        const detail = serverStderr.trim();",
    '        reject(new Error("Backend exited before it became ready (code " + code + ")." + (detail ? "\\n\\n" + detail : "")));',
    "      });",
    "    }),",
    "  ]);",
    '  console.log("[shipdesk] Server ready on port", API_PORT);',
    "}",
    "",
    "function createWindow(url) {",
    "  mainWindow = new BrowserWindow({",
    "    width: " + config.electron.window.width + ",",
    "    height: " + config.electron.window.height + ",",
    "    minWidth: 800,",
    "    minHeight: 600,",
    "    title: " + JSON.stringify(title) + ",",
    '    titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",',
    "    webPreferences: { nodeIntegration: false, contextIsolation: true },",
    "  });",
    "",
    "  mainWindow.loadURL(url);",
    "",
    '  mainWindow.webContents.setWindowOpenHandler(({ url }) => {',
    "    shell.openExternal(url);",
    '    return { action: "deny" };',
    "  });",
    "",
    '  if (isDev) mainWindow.webContents.openDevTools({ mode: "detach" });',
    '  mainWindow.on("closed", () => { mainWindow = null; });',
    "}",
    "",
    "if (gotSingleInstanceLock) {",
    '  app.on("second-instance", () => {',
    "    if (!mainWindow) return;",
    "    if (mainWindow.isMinimized()) mainWindow.restore();",
    "    mainWindow.focus();",
    "  });",
    "",
    "  app.whenReady().then(async () => {",
    "    try {",
    "      await startApiServer();",
    '      const loadUrl = isDev ? "http://localhost:" + FRONTEND_PORT : "http://localhost:" + API_PORT;',
    "      createWindow(loadUrl);",
    "    } catch (err) {",
    '      const message = err instanceof Error ? err.message : String(err);',
    '      showErrorAndQuit("Failed to start the server.\\n\\n" + message);',
    "    }",
    "",
    '    app.on("activate", () => {',
    "      if (BrowserWindow.getAllWindows().length === 0) {",
    '        const url = isDev ? "http://localhost:" + FRONTEND_PORT : "http://localhost:" + API_PORT;',
    "        createWindow(url);",
    "      }",
    "    });",
    "  });",
    "",
    '  app.on("window-all-closed", () => {',
    '    if (process.platform !== "darwin") app.quit();',
    "  });",
    "",
    '  app.on("before-quit", () => {',
    "    if (apiProcess) { apiProcess.kill(); apiProcess = null; }",
    "  });",
    "}",
  ];
}

function generateFrontendStaticSeparate(config: ShipdeskConfig): string[] {
  const title = toTitleCase(config.name);
  return [
    "// ---------------------------------------------------------------------------",
    "// Topology: frontend-static-separate",
    "// Frontend is a separate static build, needs its own HTTP server",
    "// ---------------------------------------------------------------------------",
    "",
    "function startStaticServer(port) {",
    "  return new Promise((resolve, reject) => {",
    '    const staticPath = path.join(process.resourcesPath, "server", "web-dist");',
    "    const mimeTypes = {",
    "      '.html': 'text/html',",
    "      '.js': 'application/javascript',",
    "      '.css': 'text/css',",
    "      '.json': 'application/json',",
    "      '.png': 'image/png',",
    "      '.jpg': 'image/jpeg',",
    "      '.svg': 'image/svg+xml',",
    "      '.ico': 'image/x-icon',",
    "    };",
    "",
    "    staticServer = http.createServer((req, res) => {",
    "      let filePath = path.join(staticPath, req.url === '/' ? 'index.html' : req.url);",
    "      const ext = path.extname(filePath);",
    "      const contentType = mimeTypes[ext] || 'application/octet-stream';",
    "",
    "      fs.readFile(filePath, (err, content) => {",
    "        if (err) {",
    "          if (err.code === 'ENOENT') {",
    "            fs.readFile(path.join(staticPath, 'index.html'), (err2, content2) => {",
    "              if (err2) {",
    "                res.writeHead(404);",
    "                res.end('Not found');",
    "              } else {",
    "                res.writeHead(200, { 'Content-Type': 'text/html' });",
    "                res.end(content2);",
    "              }",
    "            });",
    "          } else {",
    "            res.writeHead(500);",
    "            res.end('Server error');",
    "          }",
    "        } else {",
    "          res.writeHead(200, { 'Content-Type': contentType });",
    "          res.end(content);",
    "        }",
    "      });",
    "    });",
    "",
    '    staticServer.listen(port, () => {',
    '      console.log("[shipdesk] Static server running on port " + port);',
    "      resolve();",
    "    });",
    "",
    "    staticServer.on('error', (err) => {",
    "      reject(err);",
    "    });",
    "  });",
    "}",
    "",
    "async function startServers() {",
    "  if (isDev) {",
    "    await waitForServer(\"http://localhost:\" + FRONTEND_PORT, 30000);",
    "    console.log(\"[shipdesk] Frontend dev server ready on port\", FRONTEND_PORT);",
    "    return;",
    "  }",
    "",
    "  await startStaticServer(FRONTEND_PORT);",
    "",
    '  const serverPath = path.join(process.resourcesPath, "server", "server.mjs");',
    "  let serverStderr = \"\";",
    "  apiProcess = utilityProcess.fork(serverPath, [], {",
    "    env: { ...process.env, PORT: String(API_PORT), NODE_ENV: \"production\" },",
    "    cwd: path.dirname(serverPath),",
    "    stdio: \"pipe\",",
    '    serviceName: "shipdesk-backend",',
    "  });",
    "",
    '  apiProcess.on("spawn", () => console.log("[server] API spawned"));',
    '  apiProcess.stdout?.on("data", (d) => console.log("[server]", d.toString().trim()));',
    '  apiProcess.stderr?.on("data", (d) => {',
    "    serverStderr += d.toString();",
    '    console.error("[server:err]", d.toString().trim());',
    "  });",
    '  apiProcess.on("exit", (code) => {',
    '    console.log("[server] API exited with code", code);',
    "    apiProcess = null;",
    "  });",
    "",
    "  await Promise.race([",
    "    waitForServer(\"http://localhost:\" + API_PORT),",
    "    new Promise((_, reject) => {",
    '      apiProcess.once("exit", (code) => {',
    "        const detail = serverStderr.trim();",
    '        reject(new Error("Backend exited before it became ready (code " + code + ")." + (detail ? "\\n\\n" + detail : "")));',
    "      });",
    "    }),",
    "  ]);",
    '  console.log("[shipdesk] API server ready on port", API_PORT);',
    "}",
    "",
    "function createWindow(url) {",
    "  mainWindow = new BrowserWindow({",
    "    width: " + config.electron.window.width + ",",
    "    height: " + config.electron.window.height + ",",
    "    minWidth: 800,",
    "    minHeight: 600,",
    "    title: " + JSON.stringify(title) + ",",
    '    titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",',
    "    webPreferences: { nodeIntegration: false, contextIsolation: true },",
    "  });",
    "",
    "  mainWindow.loadURL(url);",
    "",
    '  mainWindow.webContents.setWindowOpenHandler(({ url }) => {',
    "    shell.openExternal(url);",
    '    return { action: "deny" };',
    "  });",
    "",
    '  if (isDev) mainWindow.webContents.openDevTools({ mode: "detach" });',
    '  mainWindow.on("closed", () => { mainWindow = null; });',
    "}",
    "",
    "if (gotSingleInstanceLock) {",
    '  app.on("second-instance", () => {',
    "    if (!mainWindow) return;",
    "    if (mainWindow.isMinimized()) mainWindow.restore();",
    "    mainWindow.focus();",
    "  });",
    "",
    "  app.whenReady().then(async () => {",
    "    try {",
    "      await startServers();",
    '      const loadUrl = "http://localhost:" + FRONTEND_PORT;',
    "      createWindow(loadUrl);",
    "    } catch (err) {",
    '      const message = err instanceof Error ? err.message : String(err);',
    '      showErrorAndQuit("Failed to start servers.\\n\\n" + message);',
    "    }",
    "",
    '    app.on("activate", () => {',
    "      if (BrowserWindow.getAllWindows().length === 0) {",
    '        createWindow("http://localhost:" + FRONTEND_PORT);',
    "      }",
    "    });",
    "  });",
    "",
    '  app.on("window-all-closed", () => {',
    '    if (process.platform !== "darwin") app.quit();',
    "  });",
    "",
    '  app.on("before-quit", () => {',
    "    if (apiProcess) { apiProcess.kill(); apiProcess = null; }",
    "    if (staticServer) { staticServer.close(); staticServer = null; }",
    "  });",
    "}",
  ];
}

function generateFrontendOnlyStatic(config: ShipdeskConfig): string[] {
  const title = toTitleCase(config.name);
  return [
    "// ---------------------------------------------------------------------------",
    "// Topology: frontend-only-static",
    "// No backend - just a static frontend",
    "// ---------------------------------------------------------------------------",
    "",
    "async function startStaticServer() {",
    "  if (isDev) {",
    "    await waitForServer(\"http://localhost:\" + FRONTEND_PORT, 30000);",
    "    console.log(\"[shipdesk] Frontend ready on port\", FRONTEND_PORT);",
    "    return;",
    "  }",
    "",
    "  return startStaticServerOnPort(FRONTEND_PORT);",
    "}",
    "",
    "function startStaticServerOnPort(port) {",
    "  return new Promise((resolve, reject) => {",
    '    const staticPath = path.join(process.resourcesPath, "server", "web-dist");',
    "    const mimeTypes = {",
    "      '.html': 'text/html',",
    "      '.js': 'application/javascript',",
    "      '.css': 'text/css',",
    "      '.json': 'application/json',",
    "      '.png': 'image/png',",
    "      '.jpg': 'image/jpeg',",
    "      '.svg': 'image/svg+xml',",
    "      '.ico': 'image/x-icon',",
    "    };",
    "",
    "    staticServer = http.createServer((req, res) => {",
    "      let filePath = path.join(staticPath, req.url === '/' ? 'index.html' : req.url);",
    "      const ext = path.extname(filePath);",
    "      const contentType = mimeTypes[ext] || 'application/octet-stream';",
    "",
    "      fs.readFile(filePath, (err, content) => {",
    "        if (err) {",
    "          if (err.code === 'ENOENT') {",
    "            fs.readFile(path.join(staticPath, 'index.html'), (err2, content2) => {",
    "              if (err2) {",
    "                res.writeHead(404);",
    "                res.end('Not found');",
    "              } else {",
    "                res.writeHead(200, { 'Content-Type': 'text/html' });",
    "                res.end(content2);",
    "              }",
    "            });",
    "          } else {",
    "            res.writeHead(500);",
    "            res.end('Server error');",
    "          }",
    "        } else {",
    "          res.writeHead(200, { 'Content-Type': contentType });",
    "          res.end(content);",
    "        }",
    "      });",
    "    });",
    "",
    '    staticServer.listen(port, () => {',
    '      console.log("[shipdesk] Static server running on port " + port);',
    "      resolve();",
    "    });",
    "",
    "    staticServer.on('error', (err) => {",
    "      reject(err);",
    "    });",
    "  });",
    "}",
    "",
    "function createWindow(url) {",
    "  mainWindow = new BrowserWindow({",
    "    width: " + config.electron.window.width + ",",
    "    height: " + config.electron.window.height + ",",
    "    minWidth: 800,",
    "    minHeight: 600,",
    "    title: " + JSON.stringify(title) + ",",
    '    titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",',
    "    webPreferences: { nodeIntegration: false, contextIsolation: true },",
    "  });",
    "",
    "  mainWindow.loadURL(url);",
    "",
    '  mainWindow.webContents.setWindowOpenHandler(({ url }) => {',
    "    shell.openExternal(url);",
    '    return { action: "deny" };',
    "  });",
    "",
    '  if (isDev) mainWindow.webContents.openDevTools({ mode: "detach" });',
    '  mainWindow.on("closed", () => { mainWindow = null; });',
    "}",
    "",
    "if (gotSingleInstanceLock) {",
    '  app.on("second-instance", () => {',
    "    if (!mainWindow) return;",
    "    if (mainWindow.isMinimized()) mainWindow.restore();",
    "    mainWindow.focus();",
    "  });",
    "",
    "  app.whenReady().then(async () => {",
    "    try {",
    "      await startStaticServer();",
    '      const loadUrl = "http://localhost:" + FRONTEND_PORT;',
    "      createWindow(loadUrl);",
    "    } catch (err) {",
    '      const message = err instanceof Error ? err.message : String(err);',
    '      showErrorAndQuit("Failed to start static server.\\n\\n" + message);',
    "    }",
    "",
    '    app.on("activate", () => {',
    "      if (BrowserWindow.getAllWindows().length === 0) {",
    '        createWindow("http://localhost:" + FRONTEND_PORT);',
    "      }",
    "    });",
    "  });",
    "",
    '  app.on("window-all-closed", () => {',
    '    if (process.platform !== "darwin") app.quit();',
    "  });",
    "",
    '  app.on("before-quit", () => {',
    "    if (staticServer) { staticServer.close(); staticServer = null; }",
    "  });",
    "}",
  ];
}

function toTitleCase(str: string): string {
  return str
    .replace(/[-_]/g, " ")
    .replace(/\b\w/g, (c) => c.toUpperCase());
}
